import React, {type Context, createContext} from 'react'
import {type IWidgetChartContextProps} from '@lmb-it/kitsconcerto-types'
import {BarChart, DoughnutChart, LineChart, PieChart, RadarChart, PolarAreaChart} from './elements'
import {useTheme} from "../contexts/Theme";

export const WidgetsContext: Context<Omit<IWidgetChartContextProps, 'type'>> = createContext(
        {} as Omit<IWidgetChartContextProps, 'type'>
)
WidgetsContext.displayName = 'WidgetsContext'

const Widgets = ({
                     data,
                     id = Math.random().toString(16).slice(2),
                     label,
                     enableMultipleDatasets = true,
                     enableExportButton,
                     type,
                     containerProps = {},
                     aspectRatio,
                     info,
                     horizontal = false,
                     isLoading,
                     height,
                     centerDisplay
                 }: Omit<IWidgetChartContextProps, 'colors' | 'isDarkMode'>) => {
    const {theme} = useTheme()

    const gridLines = 'rgba(0, 0, 0, 0.3)'
    const labels = 'black'

    const colors = {
        labels,
        gridLines
    }

    return (
            <WidgetsContext.Provider
                    value={{
                        data,
                        isDarkMode: theme == 'dark',
                        id,
                        label,
                        isLoading,
                        info,
                        aspectRatio,
                        horizontal,
                        containerProps,
                        enableMultipleDatasets,
                        enableExportButton,
                        colors,
                        height,
                        centerDisplay
                    }}
            >
                {type === 'BarChart' && <BarChart/>}
                {type === 'LineChart' && <LineChart/>}
                {type === 'PieChart' && <PieChart/>}
                {type === 'RadarChart' && <RadarChart/>}
                {type === 'PolarAreaChart' && <PolarAreaChart/>}
                {type === 'DoughnutChart' && <DoughnutChart/>}
            </WidgetsContext.Provider>
    )
}

export default Widgets
